import numpy as np

class SimpleImputer:
    def __init__(self, strategy: str = 'mean'):
        self.strategy = strategy

    def fit(self, X: np.ndarray) -> 'SimpleImputer':
        n_cols = X.shape[1]
        self.fill_values_ = np.zeros(n_cols)

        for j in range(n_cols):
            col = X[:, j]
            valid = col[~np.isnan(col)]
            if self.strategy == 'mean':
                self.fill_values_[j] = np.nanmean(col)
            elif self.strategy == 'median':
                self.fill_values_[j] = np.nanmedian(col)
            elif self.strategy == 'mode':
                if len(valid) == 0:
                    self.fill_values_[j] = 0.0
                else:
                    values, counts = np.unique(valid, return_counts=True)
                    self.fill_values_[j] = values[np.argmax(counts)]

        return self

    def transform(self, X: np.ndarray) -> np.ndarray:
        X_out = X.copy().astype(float)
        for j in range(X.shape[1]):
            mask = np.isnan(X_out[:, j])
            X_out[mask, j] = self.fill_values_[j]
        return X_out

    def fit_transform(self, X: np.ndarray) -> np.ndarray:
        return self.fit(X).transform(X)
